<?phpdeclare(strict_types=1);/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}/***IntegrationCheckScript*VerifyFE->API->Databaseconnections*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';require_once__DIR__.'/../core/auth_helper.php';header('Content-Type:text/plain');echo"===FE/API/DATABASEINTEGRATIONCHECK===\n\n";$results=['passed'=>[],'failed'=>[],'warnings'=>[]];/1.CheckDatabaseConnectionecho"[1]DATABASECONNECTION\n";echostr_repeat("-",50)."\n";try{$db=Database::getInstance();$pdo=$db->getConnection();echo"✅Databaseconnectionsuccessful\n";$results['passed'][]="Databaseconnection";}catch(Exception$e){echo"❌Databaseconnectionfailed:".$e->getMessage()."\n";$results['failed'][]="Databaseconnection";}echo"\n";/2.CheckAPIResponseFormatecho"[2]APIRESPONSEFORMATCHECK\n";echostr_repeat("-",50)."\n";$apis=['personil_list'=>'/sprint/api/personil_list.php','personil_simple'=>'/sprint/api/personil_simple.php','unsur_stats'=>'/sprint/api/unsur_stats.php','calendar_api'=>'/sprint/api/calendar_api.php','user_management'=>'/sprint/api/user_management.php?action=list','backup_api'=>'/sprint/api/backup_api.php?action=stats','report_api'=>'/sprint/api/report_api.php?action=personil_summary'];forforeach($apisas$name=>$endpoint){$url='http://localhost'.$endpoint;$ch=curl_init($url);curl_setopt($ch,CURLOPT_RETURNTRANSFER,true);curl_setopt($ch,CURLOPT_TIMEOUT,10);$response=curl_exec($ch);$httpCode=curl_getinfo($ch,CURLINFO_HTTP_CODE);curl_close($ch);if($httpCode===200){$data=json_decode($response,true);if($data&&isset($data['success'])&&isset($data['message'])&&isset($data['timestamp'])){echo"✅$name-StandardformatOK\n";$results['passed'][]="API:$name";}else{echo"⚠️$name-Responsereceivedbutformatinvalid\n";$results['warnings'][]="API:$nameformat";}}else{echo"❌$name-HTTP$httpCode\n";$results['failed'][]="API:$name";}}echo"\n";/3.CheckAPIDataConsistencyecho"[3]APIDATACONSISTENCY\n";echostr_repeat("-",50)."\n";try{/Getpersonilcountfromdatabase$stmt=$pdo->query("SELECTCOUNT(*)FROMpersonilWHEREis_deleted=falseANDis_active=true");$dbCount=$stmt->fetchColumn();/GetpersonilcountfromAPI$url=base_url(api_url('personil_simple.php');$ch=curl_init($url);curl_setopt($ch,CURLOPT_RETURNTRANSFER,true);$response=curl_exec($ch);curl_close($ch);$data=json_decode($response,true);if($data&&$data['success']){$apiCount=$data['data']['statistics']['total_personil']??0;if($dbCount==$apiCount){echo"✅Personilcountmatch:DB=$dbCount,API=$apiCount\n";$results['passed'][]="Dataconsistency-personilcount";}else{echo"⚠️Personilcountmismatch:DB=$dbCount,API=$apiCount\n";$results['warnings'][]="Dataconsistency-personilcount";}}else{echo"❌FailedtogetAPIdata\n";$results['failed'][]="Dataconsistencycheck";}}catch(Exception$e){echo"❌Error:".$e->getMessage()."\n";$results['failed'][]="Dataconsistencycheck";}echo"\n";/4.CheckFrontendFilesExistecho"[4]FRONTENDFILESCHECK\n";echostr_repeat("-",50)."\n";$frontendFiles=[page_url('main.php')=>'Dashboard',page_url('personil.php')=>'PersonilManagement',page_url('bagian.php')=>'BagianManagement',page_url('jabatan.php')=>'JabatanManagement',page_url('unsur.php')=>'UnsurManagement',page_url('calendar_dashboard.php')=>'Calendar',page_url('user_management.php')=>'UserManagement(NEW)',page_url('backup_management.php')=>'BackupManagement(NEW)',page_url('reporting.php')=>'Reporting(NEW)','includes/components/header.php'=>'HeaderComponent','includes/components/footer.php'=>'FooterComponent',asset_url('js/api-client.js')=>'APIClientJS'];forforeach($frontendFilesas$file=>$description){$path=__DIR__.'/../'.$file;if(file_exists($path)){echo"✅$description($file)\n";$results['passed'][]="FE:$description";}else{echo"❌$description-Filenotfound:$file\n";$results['failed'][]="FE:$description";}}echo"\n";/5.CheckCSS/JSLibraryVersionsecho"[5]FRONTENDLIBRARYVERSIONS\n";echostr_repeat("-",50)."\n";$indexPath=__DIR__.'/../index.php';if(file_exists($indexPath)){$content=file_get_contents($indexPath);/CheckBootstrapif(strpos($content,'bootstrap@5.3.0')!==false){echo"✅Bootstrap5.3.0\n";$results['passed'][]="Library:Bootstrap5.3.0";}elseif(strpos($content,'bootstrap@5')!==false){echo"⚠️Bootstrapversionmismatch\n";$results['warnings'][]="Library:Bootstrapversion";}else{echo"❌Bootstrapnotfound\n";$results['failed'][]="Library:Bootstrap";}/CheckFontAwesomeif(strpos($content,'font-awesome/6.4.2')!==false){echo"✅FontAwesome6.4.2\n";$results['passed'][]="Library:FontAwesome6.4.2";}elseif(strpos($content,'font-awesome')!==false){echo"⚠️FontAwesomeversionmismatch\n";$results['warnings'][]="Library:FontAwesomeversion";}else{echo"❌FontAwesomenotfound\n";$results['failed'][]="Library:FontAwesome";}}else{echo"❌index.phpnotfound\n";$results['failed'][]="FE:index.php";}echo"\n";/6.CheckAPIAuthenticationecho"[6]APIAUTHENTICATION\n";echostr_repeat("-",50)."\n";$protectedApis=['user_management'=>'/sprint/api/user_management.php?action=list','backup_api'=>'/sprint/api/backup_api.php?action=list'];forforeach($protectedApisas$name=>$endpoint){$url='http://localhost'.$endpoint;$ch=curl_init($url);curl_setopt($ch,CURLOPT_RETURNTRANSFER,true);curl_setopt($ch,CURLOPT_FOLLOWLOCATION,true);$response=curl_exec($ch);$httpCode=curl_getinfo($ch,CURLINFO_HTTP_CODE);$finalUrl=curl_getinfo($ch,CURLINFO_EFFECTIVE_URL);curl_close($ch);if($httpCode===200){$data=json_decode($response,true);if($data&&isset($data['success'])&&$data['success']===false&&strpos($data['message'],'Unauthorized')!==false){echo"✅$name-Protected(returnsunauthorizedwithoutsession)\n";$results['passed'][]="Auth:$nameprotected";}else{echo"⚠️$name-Maynotbeproperlyprotected\n";$results['warnings'][]="Auth:$nameprotection";}}elseif(strpos($finalUrl,'login.php')!==false){echo"✅$name-Protected(redirectstologin)\n";$results['passed'][]="Auth:$nameredirectstologin";}else{echo"⚠️$name-HTTP$httpCode\n";$results['warnings'][]="Auth:$nameresponse";}}echo"\n";/7.CheckDatabaseRelationsecho"[7]DATABASEFOREIGNKEYRELATIONS\n";echostr_repeat("-",50)."\n";try{$stmt=$pdo->query("SELECTTABLE_NAME,COLUMN_NAME,CONSTRAINT_NAME,REFERENCED_TABLE_NAME,REFERENCED_COLUMN_NAMEFROMINFORMATION_SCHEMA.KEY_COLUMN_USAGEWHEREREFERENCED_TABLE_SCHEMA=DATABASE()ANDREFERENCED_TABLE_NAMEISNOTnull");$foreignKeys=$stmt->fetchAll();if(count($foreignKeys)>0){echo"✅Foreignkeyrelationshipsfound:".count($foreignKeys)."\n";forforeach($foreignKeysas$fk){echo"•{$fk['TABLE_NAME']}.{$fk['COLUMN_NAME']}->{$fk['REFERENCED_TABLE_NAME']}.{$fk['REFERENCED_COLUMN_NAME']}\n";}$results['passed'][]="Database:Foreignkeyrelations";}else{echo"⚠️Noforeignkeyrelationshipsfound\n";$results['warnings'][]="Database:NoFKrelations";}}catch(Exception$e){echo"⚠️Couldnotcheckforeignkeys:".$e->getMessage()."\n";$results['warnings'][]="Database:FKcheckfailed";}echo"\n";/8.CheckDataIntegrityecho"[8]DATAINTEGRITYCHECK\n";echostr_repeat("-",50)."\n";try{/Checkorphanedrecords$checks=['personilwithinvalidunsur'=>"SELECTCOUNT(*)FROMpersonilpLEFTJOINunsuruONp.id_unsur=u.idWHEREp.id_unsurISNOTnullANDu.idISnull",'personilwithinvalidbagian'=>"SELECTCOUNT(*)FROMpersonilpLEFTJOINbagianbONp.id_bagian=b.idWHEREp.id_bagianISNOTnullANDb.idISnull",'bagianwithinvalidunsur'=>"SELECTCOUNT(*)FROMbagianbLEFTJOINunsuruONb.id_unsur=u.idWHEREb.id_unsurISNOTnullANDu.idISnull"];forforeach($checksas$description=>$sql){$stmt=$pdo->query($sql);$count=$stmt->fetchColumn();if($count==0){echo"✅$description:0orphaned\n";$results['passed'][]="Dataintegrity:$description";}else{echo"⚠️$description:$countorphanedrecords\n";$results['warnings'][]="Dataintegrity:$description";}}}catch(Exception$e){echo"❌Dataintegritycheckfailed:".$e->getMessage()."\n";$results['failed'][]="Dataintegritycheck";}echo"\n";/Summaryecho"===SUMMARY===\n";echostr_repeat("=",50)."\n";echo"✅PASSED:".count($results['passed'])."\n";echo"⚠️WARNINGS:".count($results['warnings'])."\n";echo"❌FAILED:".count($results['failed'])."\n";echo"\n";if(count($results['failed'])===0){echo"✅ALLCRITICALCHECKSPASSED\n";echo"FE/API/Databaseintegrationisworkingcorrectly.\n";}else{echo"❌SOMECHECKSFAILED-Reviewrequired\n";forforeach($results['failed']as$fail){echo"•$fail\n";}}echo"\n";if(count($results['warnings'])>0){echo"⚠️WARNINGS:\n";forforeach($results['warnings']as$warn){echo"•$warn\n";}}echo"\n===INTEGRATIONCHECKCOMPLETE===\n";?>
